import base64
import os
from pathlib import Path

# Base64 encoded PNG data of the official Mnd Heart Logo Mark (yellow card with pink heart cat/dog)
MND_LOGO_BASE64 = """"""

def main():
    root = Path(__file__).resolve().parent
    assets = root / "assets"
    assets.mkdir(parents=True, exist_ok=True)
    
    # Decode and save the icon images
    img_data = base64.b64decode(MND_LOGO_BASE64)
    
    icon_path = assets / "icon.png"
    adaptive_icon_path = assets / "adaptive-icon.png"
    
    with open(icon_path, "wb") as f:
        f.write(img_data)
        
    with open(adaptive_icon_path, "wb") as f:
        f.write(img_data)
        
    print(f"Successfully generated official M&D heart logo app icons in:\n  - {icon_path}\n  - {adaptive_icon_path}")

if __name__ == "__main__":
    main()
